sql:
SELECT score
FROM rating_scores
WHERE entity_id = 0 AND pillar_id = 0;

SELECT entity_id, AVG(score) AS average_rating_score
FROM rating_scores
GROUP BY entity_id;

SELECT e.entity_name, r.rating, r.dynamics, r.outlook
FROM entities e
INNER JOIN ratings r ON e.entity_id = r.entity_id;

SELECT 'Type Name: ' || type_name AS formatted_type_name
FROM rating_types
WHERE type_id = 0;

SELECT DISTINCT e.entity_name, e.sector, e.industry
FROM entities e
INNER JOIN rating_scores rs ON e.entity_id = rs.entity_id;

SELECT COUNT(*) 
FROM rating_pillars 
WHERE pillar_name = 'Financial Risk';

external_knowledge:
- 'recent ratings' refers to ratings given within the last year; 
- 'frequency of their recent ratings' refers to the count of ratings issued by each agency in the last year;
- 'those who have been quite active' means the agencies that have issued a significant number of ratings, ordered from the highest to the lowest count of ratings.

sql:
SELECT entity_name, sector
FROM entities
ORDER BY industry;
